#!/usr/bin/env node
import { spawnSync } from "node:child_process";
import fs from "node:fs";
import path from "node:path";
import { createPatch, parsePatch } from "diff";

const RED = "\x1b[31m";
const GREEN = "\x1b[32m";
const YELLOW = "\x1b[33m";
const CYAN = "\x1b[36m";
const MAGENTA = "\x1b[35m";
const BOLD = "\x1b[1m";
const DIM = "\x1b[2m";
const RESET = "\x1b[0m";

// Find prettier: check local node_modules, then fall back to PATH
function findPrettier() {
  // Try to find prettier in the current working directory's node_modules
  const localBin = path.join(process.cwd(), "node_modules", ".bin", "prettier");
  if (fs.existsSync(localBin)) {
    return localBin;
  }
  // Fall back to global prettier (assume it's in PATH)
  return "prettier";
}

const prettierBin = findPrettier();
const argv = process.argv.slice(2);

const hasCheck = argv.includes("--check");

// 1) Passthrough mode unless --check is present
if (!hasCheck) {
  const r = spawnSync(prettierBin, argv, { stdio: "inherit" });
  process.exit(r.status ?? 1);
}

// 2) Pretty-check mode: replace --check with --list-different (same args otherwise)
const baseArgs = argv.filter((a) => a !== "--check");
const listArgs = [...baseArgs.filter((a) => a !== "--list-different"), "--list-different"];

const list = spawnSync(prettierBin, listArgs, { encoding: "utf8" });

if (list.status !== 0 && !(list.stdout || "").trim()) {
  // Prettier errored (bad args, missing plugin, parse error, etc). Don't mask it.
  process.stderr.write(list.stderr || "");
  process.exit(list.status ?? 1);
}

const files = (list.stdout || "")
  .split(/\r?\n/)
  .map((s) => s.trim())
  .filter(Boolean);

if (files.length === 0) {
  // formatted
  process.exit(0);
}

console.error(`${RED}${BOLD}❌ Prettier check failed${RESET}\n`);

let errorCount = 0;

function truncate(s, n = 80) {
  const oneLine = s.replace(/\t/g, "  ").replace(/\r?\n/g, "⏎");
  return oneLine.length > n ? oneLine.slice(0, n - 1) + "…" : oneLine;
}

// Categorize the type of formatting change
function categorizeChange(beforeLine, afterLine) {
  if (!beforeLine && afterLine) {
    return { type: "insert", label: "Insert", color: GREEN, desc: "Line needs to be added" };
  }
  if (beforeLine && !afterLine) {
    return { type: "delete", label: "Delete", color: RED, desc: "Line should be removed" };
  }

  const before = beforeLine.trim();
  const after = afterLine.trim();

  // Check for whitespace-only changes
  if (before === after) {
    const beforeIndent = beforeLine.match(/^(\s*)/)[1].length;
    const afterIndent = afterLine.match(/^(\s*)/)[1].length;
    if (beforeIndent !== afterIndent) {
      const diff = afterIndent - beforeIndent;
      if (diff > 0) {
        return { type: "indent", label: "Indent", color: CYAN, desc: `Add ${diff} space${diff > 1 ? "s" : ""} of indentation` };
      } else {
        return { type: "indent", label: "Indent", color: CYAN, desc: `Remove ${-diff} space${-diff > 1 ? "s" : ""} of indentation` };
      }
    }
    // Trailing whitespace
    if (beforeLine.length > before.length && afterLine.length === after.length) {
      return { type: "whitespace", label: "Trailing ws", color: DIM, desc: "Remove trailing whitespace" };
    }
    return { type: "whitespace", label: "Whitespace", color: DIM, desc: "Fix whitespace" };
  }

  // Check for line too long (before is longer and after breaks it up or trims)
  if (before.length > 80 && after.length < before.length) {
    return { type: "line-length", label: "Line too long", color: MAGENTA, desc: "Line exceeds print width" };
  }

  // Check for semicolon changes
  if (before.replace(/;+$/, "") === after.replace(/;+$/, "")) {
    if (before.endsWith(";") && !after.endsWith(";")) {
      return { type: "semicolon", label: "Semicolon", color: YELLOW, desc: "Remove semicolon" };
    }
    return { type: "semicolon", label: "Semicolon", color: YELLOW, desc: "Add semicolon" };
  }

  // Check for quote style changes
  if (before.replace(/['"]/g, "") === after.replace(/['"]/g, "")) {
    if (before.includes('"') && after.includes("'")) {
      return { type: "quotes", label: "Quotes", color: MAGENTA, desc: 'Use single quotes' };
    }
    return { type: "quotes", label: "Quotes", color: MAGENTA, desc: "Use double quotes" };
  }

  // Check for trailing comma
  if (before.replace(/,\s*$/, "") === after.replace(/,\s*$/, "")) {
    if (!before.endsWith(",") && after.endsWith(",")) {
      return { type: "comma", label: "Comma", color: YELLOW, desc: "Add trailing comma" };
    }
    return { type: "comma", label: "Comma", color: YELLOW, desc: "Remove trailing comma" };
  }

  // Check for brace/bracket spacing: {a} vs { a }
  if (before.replace(/\s/g, "") === after.replace(/\s/g, "")) {
    return { type: "spacing", label: "Spacing", color: CYAN, desc: "Fix spacing around brackets" };
  }

  // Check for arrow function formatting
  if (before.includes("=>") || after.includes("=>")) {
    return { type: "arrow", label: "Arrow fn", color: YELLOW, desc: "Reformat arrow function" };
  }

  // Generic formatting change
  return { type: "format", label: "Format", color: YELLOW, desc: "Code style" };
}

function allHunkDiagnostics(file, original, formatted) {
  const patchText = createPatch(file, original, formatted, "original", "prettier", { context: 3 });
  const parsed = parsePatch(patchText);
  const hunks = parsed?.[0]?.hunks ?? [];

  const diags = [];

  for (const hunk of hunks) {
    let oldLine = hunk.oldStart;
    let newLine = hunk.newStart;

    let line = null;
    let col = 1;
    let beforeLine = "";
    let afterLine = "";

    // Find first changed line in this hunk
    for (let i = 0; i < hunk.lines.length; i++) {
      const l = hunk.lines[i];

      if (l.startsWith(" ")) {
        oldLine++;
        newLine++;
        continue;
      }

      if (l.startsWith("-")) {
        line = oldLine;
        beforeLine = l.slice(1);

        // Find a nearby '+' for before→after preview
        for (let j = i + 1; j < Math.min(i + 8, hunk.lines.length); j++) {
          if (hunk.lines[j].startsWith("+")) {
            afterLine = hunk.lines[j].slice(1);
            break;
          }
          if (hunk.lines[j].startsWith(" ")) break;
        }

        oldLine++;
        break;
      }

      if (l.startsWith("+")) {
        line = newLine;
        afterLine = l.slice(1);

        // Find a nearby '-' for before→after preview
        for (let j = i - 1; j >= Math.max(0, i - 7); j--) {
          if (hunk.lines[j].startsWith("-")) {
            beforeLine = hunk.lines[j].slice(1);
            break;
          }
          if (hunk.lines[j].startsWith(" ")) break;
        }

        newLine++;
        break;
      }
    }

    if (line == null) line = hunk.oldStart || hunk.newStart || 1;

    // Estimate column from first differing char when we have both sides
    if (beforeLine && afterLine) {
      const max = Math.min(beforeLine.length, afterLine.length);
      let k = 0;
      while (k < max && beforeLine[k] === afterLine[k]) k++;
      col = k + 1;
    }

    // Categorize and format the change
    const category = categorizeChange(beforeLine, afterLine);

    let message;
    if (!beforeLine && !afterLine) {
      message = "File is not formatted with Prettier";
    } else {
      const b = beforeLine ? truncate(beforeLine.trim()) : "";
      const a = afterLine ? truncate(afterLine.trim()) : "";

      if (!beforeLine) {
        message = `${GREEN}+${RESET} ${DIM}${a}${RESET}`;
      } else if (!afterLine) {
        message = `${RED}-${RESET} ${DIM}${b}${RESET}`;
      } else {
        message = `${RED}-${RESET} ${b}\n          ${GREEN}+${RESET} ${a}`;
      }
    }

    diags.push({ line, col, category, message });
  }

  // If parsePatch produced no hunks but content differs, still report once
  if (diags.length === 0 && original !== formatted) {
    diags.push({
      line: 1,
      col: 1,
      category: { type: "format", label: "Formatting", color: YELLOW },
      message: "File is not formatted with Prettier",
    });
  }

  return diags;
}

for (const file of files) {
  const original = fs.readFileSync(file, "utf8");

  // Run prettier exactly as invoked (same args/plugins/config), but output formatted text for this file.
  const fmt = spawnSync(prettierBin, [...baseArgs, file], { encoding: "utf8" });

  if (fmt.status !== 0) {
    // Don't hide real prettier failures (parse errors, missing plugin, etc.)
    process.stderr.write(fmt.stderr || "");
    process.exit(fmt.status ?? 1);
  }

  const formatted = fmt.stdout;

  if (formatted !== original) {
    const diags = allHunkDiagnostics(file, original, formatted);

    for (const { line, col, category } of diags) {
      // Format: file:line:col: error: message (rule)
      // This is compatible with VS Code, GitHub Actions problem matchers, and most editors
      const location = `${file}:${line}:${col}:`;
      const severity = `${RED}error${RESET}:`;
      const message = category.desc;
      const rule = `${DIM}(prettier/${category.type})${RESET}`;
      console.error(`${location} ${severity} ${message} ${rule}`);
      errorCount++;
    }
  }
}

if (errorCount === 0) {
  process.exit(0);
}

console.error(`\n${RED}${BOLD}✖ ${errorCount} formatting error${errorCount === 1 ? "" : "s"}${RESET}`);
console.error(`\n${DIM}Run ${RESET}${CYAN}prettier --write${RESET}${DIM} to fix automatically${RESET}\n`);
process.exit(1);
